import{_ as a,o as d,c as t,ae as n}from"./chunks/framework.CRIdhvba.js";const h=JSON.parse('{"title":"SQL 与索引优化 · 第 1 章 执行计划初识","description":"","frontmatter":{"title":"SQL 与索引优化 · 第 1 章 执行计划初识"},"headers":[],"relativePath":"career/backend/db-dev/sql-advanced/index.md","filePath":"career/backend/db-dev/sql-advanced/index.md"}'),r={name:"career/backend/db-dev/sql-advanced/index.md"};function l(i,e,o,c,s,_){return d(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="sql-与索引优化-·-第-1-章-执行计划初识" tabindex="-1">SQL 与索引优化 · 第 1 章 执行计划初识 <a class="header-anchor" href="#sql-与索引优化-·-第-1-章-执行计划初识" aria-label="Permalink to &quot;SQL 与索引优化 · 第 1 章 执行计划初识&quot;">​</a></h1><p>当你执行一条复杂 SQL 时，数据库内部会生成一份「执行计划」（Explain Plan），描述它将如何访问数据、如何使用索引。</p><h2 id="_1-1-为什么要看执行计划" tabindex="-1">1.1 为什么要看执行计划？ <a class="header-anchor" href="#_1-1-为什么要看执行计划" aria-label="Permalink to &quot;1.1 为什么要看执行计划？&quot;">​</a></h2><p>对于数据库开发工程师来说，执行计划是判断 SQL 性能问题的第一手资料：</p><ul><li>是否命中了预期索引；</li><li>是否出现了全表扫描或回表次数过多；</li><li>是否存在明显的排序、临时表、Hash Join/ Nested Loop 等操作。</li></ul><p>在后续内容中，我们会以 MySQL 为例，逐步拆解 <code>EXPLAIN</code> 输出中的各个字段，并结合真实业务场景分析索引设计的优劣。</p>',6)])])}const S=a(r,[["render",l]]);export{h as __pageData,S as default};
